Class Project Extends %RegisteredObject
{
    Property StartDate As %Date;
    Property DurationDays As %Integer;

    /// Calculate end date based on duration
    Method CalculateEndDate() As %Date
    {
        // BUGGY: Off-by-one - if duration is 1 day, end should equal start
        // Current code: start + 1 day duration = start + 1 (wrong)
        // Should be: start + 1 day duration = start (correct - 1 day includes start)
        Quit ..StartDate + ..DurationDays
    }
}

