Class TestProject Extends %RegisteredObject
{
    ClassMethod TestCalculateEndDate()
    {
        Set today = +$HOROLOG

        // 1-day project should end on start date
        Set proj1 = ##class(Project).%New()
        Set proj1.StartDate = today
        Set proj1.DurationDays = 1
        Set endDate = proj1.CalculateEndDate()
        If (endDate '= today) {
            Throw ##class(%Exception.General).%New("1-day project should end on start date")
        }

        // 7-day project starting today should end 6 days from now
        Set proj2 = ##class(Project).%New()
        Set proj2.StartDate = today
        Set proj2.DurationDays = 7
        Set endDate = proj2.CalculateEndDate()
        If (endDate '= (today + 6)) {
            Throw ##class(%Exception.General).%New("7-day project should end 6 days after start")
        }
    }
}
